const text = $json.message.text;
let n = text.toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

n = n.replace(/^(oi|ola|hey|hello|hi|e ai|eai|opa|bom dia|boa tarde|boa noite)[,!.\s]*/i, '').trim();

const patterns = [
  /^(?:qual|como)\s+(?:e|eh|esta|ta)?\s*o?\s*(?:clima|tempo)\s+(?:(?:hoje|hj|agora|amanha|a\s+amanha)\s+)*(?:em|de|na|no|para|pra)\s+(.+)/i,
  /^(?:me\s+)?(?:diz|fala|conta|mostra|informa)\s+(?:o\s+|a\s+)?(?:clima|tempo|temperatura)\s+(?:de|em|na|no|para|pra)\s+(.+)/i,
  /^(?:clima|tempo|temperatura)\s+(?:de|em|na|no)\s+(.+)/i,
  /^(?:previsao)\s+(?:do\s+tempo\s+)?(?:de|em|na|no|para|pra)\s+(.+)/i,
  /^(?:quero\s+saber)\s+(?:o\s+|a\s+)?(?:clima|tempo|temperatura)\s+(?:de|em|na|no)\s+(.+)/i,
  /^(?:ta|esta)\s+(?:chovendo|frio|calor|quente|nublado)\s+(?:em|na|no)\s+(.+)/i
];

let city = null;
for (const p of patterns) {
  const m = n.match(p);
  if (m) { city = m[1]; break; }
}

if (city) {
  city = city.replace(/\b(capital|hoje|hj|agora|amanha|por favor)\b/g, '').replace(/[?!.,;]+/g, '').replace(/\s+/g, ' ').trim();
}

if (!city || city.length < 2) {
  city = n.replace(/[?!.,;]+/g, '').replace(/\s+/g, ' ').trim();
}

const abbr = { 'sp': 'Sao Paulo', 'rj': 'Rio de Janeiro', 'bh': 'Belo Horizonte', 'poa': 'Porto Alegre', 'bsb': 'Brasilia', 'ctba': 'Curitiba', 'cwb': 'Curitiba', 'fln': 'Florianopolis', 'ssa': 'Salvador', 'rec': 'Recife', 'for': 'Fortaleza', 'gyn': 'Goiania', 'man': 'Manaus', 'nat': 'Natal' };
if (abbr[city]) { city = abbr[city]; }

return { cidade: city };

const current = $node["Consulta Clima Atual"].json;
const forecast = $json;

const cityName = current.name;
const currentTemp = Math.round(current.main.temp);
const feelsLike = Math.round(current.main.feels_like);
const humidity = current.main.humidity;
const windSpeed = (current.wind.speed * 3.6).toFixed(1);
const description = current.weather[0].description;
const icon = current.weather[0].icon;

const emojis = {
  '01': '☀️', '02': '⛅', '03': '☁️', '04': '☁️',
  '09': '🌧️', '10': '🌦️', '11': '⛈️', '13': '❄️', '50': '🌫️'
};
const emoji = emojis[icon.substring(0, 2)] || '🌡️';

const dailyMap = {};
const today = new Date().toISOString().split('T')[0];

for (const item of forecast.list) {
  const date = item.dt_txt.split(' ')[0];
  if (date === today) continue;
  if (!dailyMap[date]) {
    dailyMap[date] = { temps: [], descs: [], icons: [] };
  }
  dailyMap[date].temps.push(item.main.temp);
  dailyMap[date].descs.push(item.weather[0].description);
  dailyMap[date].icons.push(item.weather[0].icon);
}

const nextDays = Object.entries(dailyMap).slice(0, 3).map(([date, data]) => {
  const min = Math.round(Math.min(...data.temps));
  const max = Math.round(Math.max(...data.temps));
  const midIdx = Math.floor(data.descs.length / 2);
  const desc = data.descs[midIdx];
  const dayEmoji = emojis[data.icons[midIdx].substring(0, 2)] || '🌡️';
  const d = new Date(date + 'T12:00:00');
  const dayName = d.toLocaleDateString('pt-BR', { weekday: 'short' });
  return `${dayEmoji} ${dayName}: ${min}°C ~ ${max}°C — ${desc}`;
});

const forecastText = nextDays.join('\n');

return {
  prompt: `Cidade: ${cityName}\nTemperatura: ${currentTemp}°C\nSensação térmica: ${feelsLike}°C\nUmidade: ${humidity}%\nVento: ${windSpeed} km/h\nCondição: ${description}\n\nPrevisão próximos dias:\n${forecastText}`,
  fallback_message: `${emoji} *${cityName}*\n\n🌡️ Temperatura: ${currentTemp}°C\n🤗 Sensação: ${feelsLike}°C\n💧 Umidade: ${humidity}%\n💨 Vento: ${windSpeed} km/h\n📋 ${description}\n\n📅 *Próximos dias:*\n${forecastText}`
};

const fallback = $node["Processar Dados"].json.fallback_message;

return {
  fallback_message: fallback
};

const text = $json.output || $json.fallback_message || '';
let s = text;

// Fix unmatched * (bold)
const asterisks = (s.match(/\*/g) || []).length;
if (asterisks % 2 !== 0) {
  const lastIdx = s.lastIndexOf('*');
  s = s.substring(0, lastIdx) + s.substring(lastIdx + 1);
}

// Fix unmatched _ (italic)
const underscores = (s.match(/_/g) || []).length;
if (underscores % 2 !== 0) {
  const lastIdx = s.lastIndexOf('_');
  s = s.substring(0, lastIdx) + s.substring(lastIdx + 1);
}

// Fix unmatched ` (code)
const backticks = (s.match(/`/g) || []).length;
if (backticks % 2 !== 0) {
  const lastIdx = s.lastIndexOf('`');
  s = s.substring(0, lastIdx) + s.substring(lastIdx + 1);
}

// Remove unmatched [ without closing ]
s = s.replace(/\[([^\]]*$)/g, '$1');

return { text: s };
